import hashlib

def construct_merkle_tree(data):
 blocks = [data[i:i+1024] for i in range(0, len(data), 1024)]
 merkle_tree = []
 for block in blocks:
 hash = hashlib.sha256(block).hexdigest()
 merkle_tree.append(hash)
 while len(merkle_tree) > 1:
 paired_hashes = []
 for i in range(0, len(merkle_tree), 2):
 paired_hashes.append(hashlib.sha256(merkle_tree[i] + merkle_tree[i+1]).hexdigest())
 merkle_tree = paired_hashes
 return merkle_tree[0]
